// Build PQ array, ensure unique
const usedPQ = new Set();
const practiceQuestions = [];
let pqId = 1;
for (const row of PQ_RAW) {
  const [h,e,alt,hint,exp,d,tags,gr,cat] = row;
  const key = h + '|' + e;
  if (usedPQ.has(key)) continue;
  usedPQ.add(key);
  practiceQuestions.push({
    id: pqId++,
    hindi: h, english: e, alternatives: alt, hint, explanation: exp,
    difficulty: d, tags, grammarRule: gr, category: cat
  });
}

