const dailyTest = DT_RAW.slice(0,350).map((q,i) => {
  const base = {id:i+1, type:q.t};
  if(q.t==='error'){base.sentence=q.s; base.correct=q.c;}
  else if(q.t==='mcq'){base.question=q.q;}
  else {base.hindi=q.h;}
  base.options=q.o; base.answer=q.a; base.explanation=q.ex;
  return base;
});

const dtOutput = {
  day:6,
  title:`Day 6 Daily Test — Has/Have (${dailyTest.length} Questions)`,
  totalQuestions:dailyTest.length,
  timeLimit:20,
  passingScore:70,
  questions:dailyTest
};
fs.writeFileSync('data/challenge/day-06/daily-test.json', JSON.stringify(dtOutput, null, 2));
